function FlightTracker() {
  const [flight, setFlight] = React.useState('');
  const [loading, setLoading] = React.useState(false);
  const [data, setData] = React.useState(null);
  const [error, setError] = React.useState('');
  const search = async () => {
    if (!flight.trim()) return;
    setLoading(true);
    setError('');
    setData(null);
    try {
      const res = await fetch(`https://api.aviationstack.com/v1/flights?access_key=REPLACE_WITH_API_KEY&flight_iata=${flight.trim().toUpperCase()}`);
      const json = await res.json();
      if (json.data && json.data.length > 0) {
        setData(json.data[0]);
      } else {
        setError('No flight found. Try a valid IATA code (e.g. AA123).');
      }
    } catch (e) {
      setError('Request failed. Check your API key or network.');
    } finally {
      setLoading(false);
    }
  };
  const statusColor = (s) => {
    if (!s) return '#888';
    const l = s.toLowerCase();
    if (l.includes('landed') || l.includes('arrived')) return '#22c55e';
    if (l.includes('delayed')) return '#ef4444';
    if (l.includes('cancelled')) return '#dc2626';
    if (l.includes('scheduled') || l.includes('active')) return '#3b82f6';
    return '#eab308';
  };
  return (
    <div style={{ fontFamily: 'system-ui, sans-serif', padding: 16, background: '#fff', borderRadius: 12, height: '100%', boxSizing: 'border-box', display: 'flex', flexDirection: 'column' }}>
      <h3 style={{ margin: '0 0 10px 0', fontSize: 16, color: '#222' }}>Flight Tracker</h3>
      <div style={{ display: 'flex', gap: 8, marginBottom: 10 }}>
        <input value={flight} onChange={(e) => setFlight(e.target.value)} onKeyDown={(e) => e.key === 'Enter' && search()} placeholder="Flight number (e.g. AA123)" style={{ flex: 1, padding: '6px 10px', borderRadius: 8, border: '1px solid #ddd', fontFamily: 'inherit', fontSize: 13, textTransform: 'uppercase' }} />
        <button onClick={search} disabled={loading} style={{ padding: '6px 12px', borderRadius: 8, border: 'none', background: '#4f46e5', color: '#fff', cursor: 'pointer', fontFamily: 'inherit', fontWeight: 500, opacity: loading ? 0.7 : 1 }}>{loading ? '...' : 'Track'}</button>
      </div>
      {error && <div style={{ padding: 10, borderRadius: 8, background: '#fef2f2', color: '#b91c1c', fontSize: 13, marginBottom: 10 }}>{error}</div>}
      {data && (
        <div style={{ flex: 1, overflow: 'auto' }}>
          <div style={{ display: 'flex', alignItems: 'center', gap: 8, marginBottom: 10 }}>
            <span style={{ fontSize: 13, fontWeight: 600, color: '#333' }}>{data.airline?.name} {data.flight?.iata}</span>
            <span style={{ padding: '2px 8px', borderRadius: 99, background: statusColor(data.flight_status) + '15', color: statusColor(data.flight_status), fontSize: 12, fontWeight: 600, textTransform: 'capitalize' }}>{data.flight_status}</span>
          </div>
          <div style={{ display: 'grid', gridTemplateColumns: '1fr auto 1fr', gap: 8, alignItems: 'center', marginBottom: 10 }}>
            <div style={{ textAlign: 'center' }}>
              <div style={{ fontSize: 24, fontWeight: 700, color: '#222' }}>{data.departure?.iata}</div>
              <div style={{ fontSize: 11, color: '#888' }}>{data.departure?.airport}</div>
              <div style={{ fontSize: 12, color: '#555', marginTop: 2 }}>{data.departure?.scheduled ? new Date(data.departure.scheduled).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }) : '—'}</div>
            </div>
            <div style={{ textAlign: 'center', color: '#aaa' }}>✈</div>
            <div style={{ textAlign: 'center' }}>
              <div style={{ fontSize: 24, fontWeight: 700, color: '#222' }}>{data.arrival?.iata}</div>
              <div style={{ fontSize: 11, color: '#888' }}>{data.arrival?.airport}</div>
              <div style={{ fontSize: 12, color: '#555', marginTop: 2 }}>{data.arrival?.scheduled ? new Date(data.arrival.scheduled).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }) : '—'}</div>
            </div>
          </div>
          <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 8 }}>
            <div style={{ padding: 8, borderRadius: 8, background: '#f8f8f8', fontSize: 12 }}>
              <div style={{ color: '#888', marginBottom: 2 }}>Terminal / Gate</div>
              <div style={{ color: '#333', fontWeight: 500 }}>{data.departure?.terminal || '—'} / {data.departure?.gate || '—'}</div>
            </div>
            <div style={{ padding: 8, borderRadius: 8, background: '#f8f8f8', fontSize: 12 }}>
              <div style={{ color: '#888', marginBottom: 2 }}>Arrival Terminal / Gate</div>
              <div style={{ color: '#333', fontWeight: 500 }}>{data.arrival?.terminal || '—'} / {data.arrival?.gate || '—'}</div>
            </div>
          </div>
        </div>
      )}
      {!data && !error && !loading && (
        <div style={{ flex: 1, display: 'flex', alignItems: 'center', justifyContent: 'center', color: '#bbb', fontSize: 13 }}>
          Enter a flight number to track
        </div>
      )}
    </div>
  );
}
render(<FlightTracker/>);
